body { margin: 0; overflow: hidden; background-color: #ffffff; }
        canvas { display: block; }

        .lil-gui.root {
            position: absolute;
            bottom: 20px;
            right: 20px;
            top: auto !important;
        }

        #loader {
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            font-family: sans-serif;
            font-size: 14px;
            color: #555;
            background: rgba(255, 255, 255, 0.9);
            padding: 15px 30px;
            border-radius: 8px;
            pointer-events: none;
            transition: opacity 0.3s;
        }
